import 'package:flutter/material.dart';\n\nclass NearaLogo extends StatelessWidget {\n  final double? width;\n  final double? height;\n  final Color? color;\n  final bool showText;\n  final double? fontSize;\n  \n  const NearaLogo({\n    super.key,\n    this.width = 120,\n    this.height = 120,\n    this.color,\n    this.showText = false,\n    this.fontSize = 24,\n  });\n\n  @override\n  Widget build(BuildContext context) {\n    return Column(\n      mainAxisSize: MainAxisSize.min,\n      children: [\n        Image.asset(\n          'assets/images/neara_logo.png',\n          width: width,\n          height: height,\n          fit: BoxFit.contain,\n          color: color, // Tint the logo if color is provided\n          colorBlendMode: color != null ? BlendMode.srcIn : null,\n          errorBuilder: (context, error, stackTrace) {\n            // Fallback UI if logo image fails to load\n            return Container(\n              width: width,\n              height: height,\n              decoration: const BoxDecoration(\n                shape: BoxShape.circle,\n                gradient: LinearGradient(\n                  colors: [Color(0xFF00E5FF), Color(0xFF00B4DB)],\n                ),\n              ),\n              child: const Center(\n                child: Text(\n                  'N',\n                  style: TextStyle(\n                    fontSize: 48,\n                    fontWeight: FontWeight.bold,\n                    color: Colors.white,\n                  ),\n                ),\n              ),\n            );\n          },\n        ),\n        if (showText) ..[\n          const SizedBox(height: 8),\n          Text(\n            'NEARA',\n            style: TextStyle(\n              fontSize: fontSize,\n              fontWeight: FontWeight.bold,\n              color: color ?? Theme.of(context).primaryColor,\n              letterSpacing: 2.0,\n            ),\n          ),\n        ],\n      ],\n    );\n  }\n}\n\n/// Compact logo for app bars and small spaces\nclass NearaLogoCompact extends StatelessWidget {\n  final double size;\n  final Color? color;\n  \n  const NearaLogoCompact({\n    super.key,\n    this.size = 32,\n    this.color,\n  });\n\n  @override\n  Widget build(BuildContext context) {\n    return NearaLogo(\n      width: size,\n      height: size,\n      color: color,\n      showText: false,\n    );\n  }\n}\n\n/// Large logo for splash screens and onboarding\nclass NearaLogoBrand extends StatelessWidget {\n  final Color? color;\n  \n  const NearaLogoBrand({\n    super.key,\n    this.color,\n  });\n\n  @override\n  Widget build(BuildContext context) {\n    return NearaLogo(\n      width: 200,\n      height: 200,\n      color: color,\n      showText: true,\n      fontSize: 32,\n    );\n  }\n}